"""
mkt-christ | Exodus | 33-35
Script: zc-christ-exodus-33-35-fill.py
Run: python3 scripts/zc-christ-exodus-33-35-fill.py

Ch 33: Moses's intercession, tent of meeting outside the camp, face-to-face dialogue, glory request
Ch 34: Second tablets, divine name proclaimed (hesed w'emet = John 1:14), Moses's shining face and veil (2 Cor 3)
Ch 35: Sabbath ordinance, voluntary offerings, Bezalel filled with the Spirit (first explicit Spirit-filling in OT)

Key typological threads:
- Ex 34:6 hesed w'emet -> John 1:14 'full of grace and truth' (direct NT echo of Sinai name-proclamation)
- Ex 34:29-35 Moses's shining face / veil -> 2 Cor 3:7-18 Paul's extended typology of new-covenant glory
- Ex 35:31 Bezalel filled with the Spirit of God -> Isa 11:2 / Luke 4:18 / Acts 10:38 (Spirit on the Messiah)
- Ex 33:14 'I will give you rest' -> Matt 11:28-29 Jesus appropriates YHWH's exact promise
- Ex 33:20-22 no one sees God's face and lives -> John 1:18 / 2 Cor 4:6 resolved in Christ
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

EXODUS = {
    "33": {
        "1": "<p>A theme: YHWH commands departure toward the promised land. Christ leads his people to their inheritance (Heb 3:6; 1 Pet 1:3-5), and his promise in Matt 28:20 &mdash; 'I am with you always' &mdash; reverses the withdrawal announced in the following verses.</p>",
        "2": "<p>A shadow: an angel (<em>mal'ak</em>) sent before them. The angel of YHWH in Ex 3:2 was identified with YHWH himself; Christ is not a mere envoy but the Presence itself (John 1:14; Col 1:15-17). Rev 22:16 names the risen Christ as the one who sends the messenger.</p>",
        "3": "<p>A theme: 'I will not go up in your midst, lest I consume you, for you are a stiff-necked people.' The withdrawal of divine Presence because of sin is the exact problem the incarnation resolves. Christ enters human community not to consume but to save (Matt 1:21; Luke 9:56). Heb 10:19-22 now opens the Most Holy Place for all who come through him.</p>",
        "4": "<p>A theme: Israel mourned when they heard this troubling word; no one put on ornaments. The absence of God's Presence is mourning itself. Matt 9:15: 'Can the wedding guests mourn while the bridegroom is with them?' The presence of Christ reverses the cause of mourning (Rev 21:4).</p>",
        "5": "<p>A revelation of God: 'You are a stiff-necked people; if I go with you for even a moment I would consume you.' The terror of divine holiness that cannot dwell with unrepentant sin. Christ as the Lamb of God absorbs this consuming judgment so that sinners may stand (John 1:29; 2 Cor 5:21; Heb 9:14).</p>",
        "6": "<p>A theme: Israel stripped off their ornaments at Horeb &mdash; a gesture of mourning and acknowledged unworthiness. Luke 15:17-24: the returning prodigal relinquishes all claim to status and is clothed by the father's grace. Unworthiness is met not with rejection but with the covering of the mediator.</p>",
        "7": "<p>A type: the tent of meeting (<em>ohel mo'ed</em>) placed outside the camp, away from the sinful community. Heb 13:12-13: 'Jesus suffered outside the gate... let us go to him outside the camp, bearing the disgrace he bore.' The meeting place of the new covenant is outside the center of human social respectability &mdash; Christ crucified outside Jerusalem's walls.</p>",
        "8": "<p>A theme: the people rose and watched Moses until he had entered the tent. The community watching the mediator approach God on their behalf. 1 Tim 2:5: 'there is one mediator between God and men, the man Christ Jesus.' Heb 9:24: Christ 'entered heaven itself, now to appear in the presence of God on our behalf.'</p>",
        "9": "<p>A type: the pillar of cloud descended at the tent entrance when Moses entered; YHWH spoke with Moses. The cloud as the Spirit's presence (1 Cor 10:1-2). At Jesus's baptism the Spirit descends as a dove and the Father speaks (Matt 3:16-17), making the same pattern explicit at the new covenant's inauguration.</p>",
        "10": "<p>A theme: all the people rose and worshiped at their tent doors when the cloud descended. The visible presence of God with the mediator draws the whole community to worship. Rev 5:11-14: every creature worshiping the Lamb who has made access to the Presence possible.</p>",
        "11": "<p>A type and its limit: 'YHWH spoke to Moses face to face, as a man speaks with his friend.' Moses is the greatest OT type of Christ as mediator, yet John 1:18 marks the type's boundary: 'No one has seen God at any time; the only-begotten Son, who is in the bosom of the Father, has made him known.' Christ does not speak with God as a friend &mdash; he speaks from within the divine life as God the Son.</p>",
        "12": "<p>A type: Moses intercedes on the basis of divine intimacy &mdash; 'You have said I know you by name and you have found favor with me.' John 10:14-15: 'I know my sheep and my sheep know me &mdash; just as the Father knows me and I know the Father.' Christ intercedes from within the mutual divine knowing; his intercession succeeds because he is beloved of the Father (John 17:24-26).</p>",
        "13": "<p>A theme: 'Show me your ways, that I may know you.' The pursuit of knowing God as the heart of the covenant life. Phil 3:8-10: 'I count everything as loss... that I may know him.' John 14:6-9: Christ is himself the answer to Moses's request &mdash; 'the one who has seen me has seen the Father.'</p>",
        "14": "<p>A direct type: 'My Presence will go with you, and I will give you rest.' Matt 11:28-29: Jesus appropriates the exact language of YHWH's promise &mdash; 'Come to me, all who are weary and burdened, and I will give you rest.' Heb 4:1-11: the rest YHWH promises here is the eschatological sabbath rest that Christ opens; he is the Presence and the rest in one person.</p>",
        "15": "<p>A theme: 'If your Presence does not go with us, do not bring us from here.' The indispensability of divine Presence for the covenant community's existence. John 15:5: 'Apart from me you can do nothing' &mdash; Christ makes the same claim in inverted form; without his presence the mission is not merely difficult but impossible.</p>",
        "16": "<p>A theme: God's Presence going with Israel is what distinguishes them from all other peoples on earth. The indwelling Spirit as the distinguishing mark of the new covenant community (Gal 3:2-5; 1 Cor 12:13; Eph 1:13-14; Rom 8:9): not ethnicity or law-observance but Christ's Spirit within constitutes the people of God.</p>",
        "17": "<p>A type: YHWH grants Moses's intercession because Moses has found favor and is known by name. Heb 7:25: 'he always lives to make intercession for them.' John 17:9,24: Christ intercedes and is heard because the Father loves him. The successful intercession of Moses is a pattern of Christ's intercession that never fails.</p>",
        "18": "<p>A type: 'Show me your glory' &mdash; the deepest request of the OT's greatest intercessor. John 12:41: Isaiah saw Christ's glory and spoke about him. John 14:8-9: Philip asks 'Show us the Father' and Jesus replies 'Whoever has seen me has seen the Father.' The Transfiguration (Matt 17:1-8) is the earthly partial fulfillment; the new Jerusalem is its completion (Rev 21:23).</p>",
        "19": "<p>A revelation of God: 'I will be gracious to whom I will be gracious, and show mercy to whom I will show mercy.' Paul cites Ex 33:19 in Rom 9:15 to establish the sovereign freedom of divine mercy &mdash; grace is never earned. Eph 2:4-9: salvation rests entirely on this freedom, 'not from works, so that no one may boast.'</p>",
        "20": "<p>A revelation of God: 'You cannot see my face, for no one may see me and live.' John 1:18 resolves this: 'No one has seen God at any time; the only-begotten Son, who is in the bosom of the Father, has made him known.' Heb 1:3: Christ as 'the radiance of God's glory and the exact representation of his being' &mdash; the incarnation is the answer to this terrifying impossibility. 2 Cor 4:6: the light of the knowledge of God's glory is now seen 'in the face of Christ.'</p>",
        "21": "<p>A type: 'There is a place near me where you shall stand on the rock.' 1 Cor 10:4: 'that Rock was Christ.' The designated place of safety near God is the Rock himself. Eph 2:6: believers are 'raised up with him and seated with him in the heavenly places in Christ Jesus' &mdash; to stand on the Rock is to stand in Christ.</p>",
        "22": "<p>A type: 'I will put you in a cleft of the rock, and cover you with my hand until I have passed by.' 1 Cor 10:4 identifies the Rock as Christ; Col 3:3: 'your life is hidden with Christ in God.' The cleft of the Rock is union with Christ; his covering hand = his righteousness sheltering the one who is in him (2 Cor 5:21).</p>",
        "23": "<p>A shadow: 'You will see my back, but my face will not be seen' &mdash; the characteristic mode of OT revelation: mediated, partial, from behind. 2 Cor 3:14-18: the veil lying over the old covenant. But John 14:9 and 2 Cor 4:6 invert this entirely: in Christ's face the full knowledge of God's glory is now directly accessible to all who turn to him.</p>"
    },
    "34": {
        "1": "<p>A type: the second stone tablets &mdash; covenant renewal after apostasy. Jer 31:31-34; Heb 8:8-12 (the new covenant written on hearts, not stone). 2 Cor 3:3: 'written not on tablets of stone but on tablets of human hearts by the Spirit of the living God.' The broken law is renewed; but the new covenant internalizes it.</p>",
        "2": "<p>A theme: Moses to present himself at Sinai's summit in the morning. Morning as the time of covenant encounter: the Resurrection at dawn (Mark 16:2; John 20:1) as the morning that supersedes all prior Sinai mornings. Rev 22:16: Christ as 'the bright morning star.'</p>",
        "3": "<p>A type: no one to accompany Moses; the mediator goes alone into God's presence. Heb 9:7,11-12: the high priest entered the Most Holy Place alone; Christ entered the heavenly sanctuary once for all, alone, with his own blood &mdash; no accompanying intercession needed or permitted.</p>",
        "4": "<p>A type: Moses cut the tablets and rose early in the morning to go up. A type of Christ's willing, early-rising obedience: Mark 1:35 (Jesus rises before dawn for prayer); Heb 12:2 'who for the joy set before him endured the cross, despising the shame' &mdash; going toward God's presence without hesitation.</p>",
        "5": "<p>A type: YHWH descended in the cloud and stood with Moses; he proclaimed the name YHWH. John 1:14: 'the Word became flesh and <em>eskenos</em> among us' &mdash; the divine condescension at Sinai prefigures the permanent, final descent of God into human flesh at the incarnation.</p>",
        "6": "<p>A direct type: 'YHWH, YHWH, the compassionate and gracious God, slow to anger, abounding in <em>hesed</em> and <em>emet</em> (steadfast love and faithfulness).' John 1:14: 'full of grace and truth (<em>charis kai aletheia</em>)' is the NT rendering of <em>hesed w'emet</em>. John 1:17: 'grace and truth came through Jesus Christ.' This is the foundational OT self-proclamation of God's character that Christ personally embodies &mdash; the most direct OT-NT verbal echo in the Gospel of John.</p>",
        "7": "<p>A revelation of God: 'keeping <em>hesed</em> for thousands, forgiving iniquity and transgression and sin, but who will by no means clear the guilty.' The tension between mercy and justice that the cross alone resolves. Rom 3:25-26: God presented Christ as a <em>hilasterion</em> so that he might be 'just and the justifier of the one who has faith in Jesus' &mdash; Ex 34:7 is satisfied on both sides at Calvary.</p>",
        "8": "<p>A theme: Moses bowed his head to the ground and worshiped. The fitting response to the divine name's proclamation is prostration in worship. Rev 5:8-14: all creation falls down before the Lamb who embodies the character of Ex 34:6-7 perfectly.</p>",
        "9": "<p>A type: Moses intercedes for the stiff-necked people to be pardoned and taken as God's inheritance. Heb 7:25: 'he always lives to make intercession for them.' John 17:9-26: Christ's High Priestly Prayer claims the same ground &mdash; 'they are yours... I am asking on their behalf.'</p>",
        "10": "<p>A type: 'I am making a covenant... I will do wonders (<em>nipla'ot</em>) never done before in all the earth.' Covenant renewal with fresh divine wonders. Heb 8:6-13: the new covenant is 'better, enacted on better promises.' The wonders of Exodus are surpassed by the resurrection &mdash; the greatest wonder in all the earth (Acts 2:22-24; 1 Cor 15:20-22).</p>",
        "11": "<p>A type: YHWH commands the expulsion of the Canaanites before Israel. Col 2:15: 'having disarmed the rulers and authorities, he put them to open shame, triumphing over them in him.' Christ expels the hostile spiritual powers that oppose God's covenant people.</p>",
        "12": "<p>A theme: 'Take care, lest you make a covenant with the inhabitants of the land.' The danger of spiritual compromise with what is under divine judgment. 2 Cor 6:14-16: 'Do not be unequally yoked with unbelievers... what accord has Christ with Belial?' The new covenant community's distinctiveness is non-negotiable.</p>",
        "13": "<p>A shadow: 'You shall tear down their altars and break their pillars.' John 2:14-17: the cleansing of the temple &mdash; Christ's covenant confrontation with compromised worship. Zeal for God's house (Ps 69:9; John 2:17) is the characteristic mark of the true covenant keeper.</p>",
        "14": "<p>A revelation of God: 'You shall not worship any other god, for YHWH &mdash; his name is Jealous &mdash; is a jealous God.' Divine jealousy as covenant commitment to his people's ultimate welfare. 2 Cor 11:2: Paul's 'godly jealousy'; John 14:6 and Rev 2-3: the exclusive claim of Christ is the new covenant form of this fidelity.</p>",
        "15": "<p>A theme: making covenants with pagan nations leads to spiritual unfaithfulness. The language of spiritual adultery applies to the church (Jas 4:4; Rev 2-3 letters to the seven churches). The church's exclusive loyalty is to Christ as bridegroom (2 Cor 11:2; Rev 19:7-9).</p>",
        "16": "<p>A theme: intermarriage with pagans draws Israel into their gods. 2 Cor 6:14: 'Do not be unequally yoked with unbelievers.' The covenant community maintains its distinctiveness because it is betrothed to Christ (Eph 5:25-27; Rev 21:2).</p>",
        "17": "<p>A theme: 'You shall not make for yourself molten gods.' The continuing prohibition against self-made worship objects. 1 John 5:21: 'Little children, keep yourselves from idols.' Col 3:5: covetousness is idolatry. The prohibition extends beyond images to anything that displaces the centrality of Christ.</p>",
        "18": "<p>A type: keep the Feast of Unleavened Bread. 1 Cor 5:7-8: 'Christ, our Passover lamb, has been sacrificed. Therefore let us keep the feast, not with old leaven of malice and evil, but with the unleavened bread of sincerity and truth.' The feast finds its fulfillment in the ongoing life of the new covenant community.</p>",
        "19": "<p>A direct type: 'All the firstborn males are mine.' Luke 2:22-24: Mary and Joseph present Jesus at the temple in direct fulfillment of this law. Col 1:15,18: Christ as 'the firstborn over all creation' and 'the firstborn from the dead' &mdash; the one to whom all the firstborn legislation ultimately points.</p>",
        "20": "<p>A type: redeem the firstborn donkey with a lamb; redeem your firstborn sons. 1 Pet 1:18-19: 'redeemed... not with perishable things like silver or gold, but with the precious blood of Christ, like that of a lamb without blemish or defect.' Gal 3:13: 'Christ redeemed us from the curse of the law.' Every redemption price in the OT is a shadow of his.</p>",
        "21": "<p>A shadow: the Sabbath command embedded in covenant renewal. Col 2:16-17: the sabbath is a shadow of things to come; the substance belongs to Christ. Heb 4:9-11: 'there remains a sabbath rest for the people of God... let us strive to enter that rest.' Christ's finished work ('It is finished' &mdash; John 19:30) is its basis.</p>",
        "22": "<p>A type: the Feast of Weeks (Shavuot/Pentecost) and the Feast of Ingathering. Acts 2 fulfills the Feast of Weeks &mdash; the outpouring of the Spirit at Pentecost is the first-fruits harvest of the new covenant. The Feast of Ingathering at year's end points to the eschatological harvest (Rev 14:14-16; Matt 13:39).</p>",
        "23": "<p>A theme: three times a year all males shall appear before YHWH. The required access to God's presence as covenant privilege. Heb 10:19-22: 'we have confidence to enter the Most Holy Place by the blood of Jesus, by the new and living way.' The obligation becomes a gift &mdash; free and perpetual access through Christ.</p>",
        "24": "<p>A theme: YHWH will enlarge the territory and protect the people while they go up. Heb 13:6: 'The Lord is my helper; I will not fear. What can man do to me?' The covenant community's vulnerability during worship is covered by divine protection. 1 Pet 5:7: 'Cast all your anxiety on him because he cares for you.'</p>",
        "25": "<p>A shadow: blood sacrifice not offered with leavened bread; Passover lamb not to remain overnight. Heb 9:14: Christ 'through the eternal Spirit offered himself without blemish to God' &mdash; the true Passover sacrifice is perfect, complete, and unrepeatable. 1 Cor 5:7: 'Christ, our Passover lamb, has been sacrificed.'</p>",
        "26": "<p>A direct type: 'The best of the first-fruits of your ground you shall bring to the house of YHWH your God.' 1 Cor 15:20,23: 'Christ has been raised from the dead, the first-fruits of those who have fallen asleep... Christ the first-fruits, then at his coming those who belong to Christ.' The first-fruits law directly encodes the resurrection pattern.</p>",
        "27": "<p>A type: 'Write these words, for in accordance with these words I have made a covenant with you and with Israel.' The written covenant. 2 Cor 3:3: the new covenant is 'written not with ink but with the Spirit of the living God, not on tablets of stone but on tablets of human hearts.' The external writing gives way to the internal.</p>",
        "28": "<p>A type: Moses was with YHWH forty days and forty nights without eating or drinking; he wrote the Ten Words. Jesus's forty-day wilderness fast (Matt 4:1-2) recapitulates Moses's forty days. The true Israel, filled with the Spirit, succeeds where Israel repeatedly fails; his forty days end in victory, not apostasy.</p>",
        "29": "<p>A type: Moses came down from Sinai, his face shining because he had been speaking with God. The Transfiguration (Matt 17:2 'his face shone like the sun') is the NT fulfillment. But Moses's glory was reflected and fading; Christ's is intrinsic and permanent (Heb 1:3; 2 Cor 3:7-11). The glory Moses reflected Christ possessed from eternity.</p>",
        "30": "<p>A type: Aaron and all Israel saw Moses's shining face and were afraid to approach. Heb 12:19-21: the terrifying appearances of the old covenant were such that even Moses said 'I tremble with fear.' Matt 17:6-7: at the Transfiguration the disciples fell face-down in terror &mdash; but Jesus touched them and said 'Rise, and have no fear.' The new covenant replaces Sinai's terror with welcome.</p>",
        "31": "<p>A theme: Moses called to Aaron and the leaders; they returned to him. The mediator summons the community into God's presence after the terrifying display. Matt 11:28: 'Come to me, all who are weary and burdened, and I will give you rest.' Christ's summons issues after the display of who he is, not in spite of it.</p>",
        "32": "<p>A type: Moses gave all the commands YHWH had spoken on Sinai. John 1:17: 'the law was given through Moses; grace and truth came through Jesus Christ.' Moses conveys the commandments; Christ fulfills and embodies them (Matt 5:17; Rom 13:10; 2 Cor 1:20).</p>",
        "33": "<p>A direct type: after speaking to the Israelites Moses put a veil (<em>masveh</em>) over his face. 2 Cor 3:13: 'Moses put a veil over his face so that the Israelites might not gaze at the outcome of what was being brought to an end.' The veil conceals the fading, provisional character of the Mosaic covenant &mdash; its glory real but temporary.</p>",
        "34": "<p>A direct type: when Moses went before YHWH he removed the veil. 2 Cor 3:16: 'when one turns to the Lord, the veil is removed.' In Paul's argument 'the Lord' is identified with the Spirit (v17) and with Christ (1 Cor 15:45; 2 Cor 3:17) &mdash; turning to Christ removes what the veil represents: the opacity of the old covenant.</p>",
        "35": "<p>A direct type: the Israelites saw Moses's face shining; he put the veil back until he went before YHWH again. 2 Cor 3:18: 'We all, with unveiled face, beholding the glory of the Lord, are being transformed into the same image from one degree of glory to another &mdash; this comes from the Lord who is the Spirit.' The new covenant removes the veil permanently; ongoing transformation into Christ's image is the result.</p>"
    },
    "35": {
        "1": "<p>A theme: Moses assembled the whole congregation (<em>qahal</em>). The <em>qahal</em> (assembly) is the OT counterpart to the NT <em>ekklesia</em> (called-out assembly). Matt 16:18: 'I will build my church.' The community gathered around the mediator's transmission of God's word is the founding form of the people of God.</p>",
        "2": "<p>A shadow: six days for work; the seventh day a holy sabbath of rest to YHWH &mdash; whoever works on it shall be put to death. Col 2:16-17: the sabbath is a shadow of things to come; the substance is Christ. Heb 4:9-11: 'there remains a sabbath rest for the people of God.' Christ's finished work ('It is finished' &mdash; John 19:30) is the ground on which all true sabbath rests.</p>",
        "3": "<p>A shadow: 'You shall kindle no fire in all your dwelling places on the sabbath day.' The totality of sabbath rest: no work of any kind. Heb 4:10: 'whoever has entered God's rest has also rested from his works as God did from his.' To rest in Christ is to stop all effort to earn what he has freely accomplished.</p>",
        "4": "<p>A theme: Moses told the whole congregation to bring a contribution to YHWH from whoever has a willing heart. The voluntary giving of God's people for God's dwelling. 2 Cor 9:6-7: 'whoever sows generously will also reap generously... God loves a cheerful giver.' The principle is the same across both covenants; only the dwelling has changed.</p>",
        "5": "<p>A type: 'Whoever is of a generous heart, let him bring YHWH's contribution.' The willing heart as the mark of the new covenant community. Jer 31:33: YHWH will write his law on their hearts. Ezek 36:26: 'I will give you a new heart and a new spirit.' 2 Cor 9:7: the new covenant community gives from a heart transformed, not coerced.</p>",
        "6": "<p>A shadow: blue, purple, and scarlet yarn, fine linen, and goat hair. The fabric contributions for the tabernacle. As in Ex 25-27: royal purple (Christ as King), priestly blue (heavenly intercession), sacrificial scarlet (blood of the covenant), pure white linen (Christ's righteousness). The palette of the dwelling encodes who Christ is.</p>",
        "7": "<p>A shadow: ram skins dyed red, fine leather (<em>tachash</em>), and acacia wood. The red-dyed ram skins as atonement covering, linked to the substituted ram (Gen 22:13). Acacia wood (imperishable desert hardwood) as a type of Christ's incorruptible humanity: Ps 16:10 'you will not let your Holy One see decay'; Acts 2:27.</p>",
        "8": "<p>A type: oil for the light, spices for the anointing oil and fragrant incense. The oil as a type of the Spirit (Zech 4:6; 1 John 2:27). Christ is anointed with the Spirit without measure (John 3:34; Acts 10:38) &mdash; the true anointing that all OT anointing shadows. The incense = his intercession continuously before the Father (Rev 8:3-4; Heb 7:25).</p>",
        "9": "<p>A shadow: onyx stones and gems for the ephod and breastpiece. The high priest bearing Israel's twelve names on his shoulders and over his heart &mdash; a type of Christ interceding with his people's names before the Father (Heb 7:25; John 17:6-26). He knows each by name and bears them continually before God.</p>",
        "10": "<p>A theme: 'Let every skilled craftsman among you come and make all that YHWH has commanded.' The Spirit-gifted community called to build God's dwelling. 1 Cor 3:9-10: 'you are God's building... like a skilled master builder I laid a foundation.' Eph 2:21-22: the church 'grows into a holy temple in the Lord, built together into a dwelling place for God by the Spirit.'</p>",
        "11": "<p>A type: the tabernacle with all its coverings, clasps, boards, bars, pillars, and bases. The tabernacle as a whole is a type of Christ's body: John 2:19-21 'Destroy this temple, and in three days I will raise it up &mdash; he was speaking about the temple of his body.' Christ is the true and final dwelling of God among his people.</p>",
        "12": "<p>A direct type: the ark with its poles and the mercy seat (<em>kapporet</em>, H3727). The mercy seat is the OT <em>hilasterion</em>: Rom 3:25 'God presented Christ as a propitiation (<em>hilasterion</em>).' Heb 9:5: the cherubim of glory overshadow the mercy seat. In the new covenant Christ himself is the meeting point between divine holiness and human need.</p>",
        "13": "<p>A type: the table with its poles, vessels, and bread of the presence. John 6:48: 'I am the bread of life.' Christ is the true bread of the presence, perpetually before the Father. The Lord's Supper is the new covenant form of the bread that remained continually before YHWH (Matt 26:26; 1 Cor 11:23-26).</p>",
        "14": "<p>A type: the lampstand for the light with its utensils and oil. John 8:12: 'I am the light of the world.' Rev 1:20: the seven churches are lampstands holding the light of Christ before a dark world. The oil &mdash; the Spirit &mdash; keeps the flame burning: Zech 4:1-6; Acts 1:8.</p>",
        "15": "<p>A type: the altar of incense with its poles; the anointing oil; the fragrant incense. Rev 8:3-4: the incense at the golden altar mixes with the prayers of the saints and rises before God. Christ's intercession is the incense that makes all prayer acceptable (Heb 7:25; Rom 8:34).</p>",
        "16": "<p>A type: the altar of burnt offering with its bronze grating, poles, vessels, and the bronze basin. Heb 13:10,12: 'we have an altar... Jesus suffered outside the gate.' The altar of burnt offering is the OT cross &mdash; the place of complete sacrifice consumed by the fire of divine holiness. John 19:34: water and blood from Christ's side echo the laver and the altar together.</p>",
        "17": "<p>A shadow: the hangings of the court, pillars, bases, and the gate screen. The court's enclosure defines the space of access to God's presence &mdash; a graduated approach. Eph 2:18: 'through him we both have access in one Spirit to the Father.' The barriers of the court give way to unhindered access through Christ (Heb 10:19-22).</p>",
        "18": "<p>A theme: the pegs of the tabernacle and the court, with their cords. The structural anchors that hold the entire dwelling in place. 1 Cor 3:11: 'no one can lay a foundation other than the one already laid, which is Jesus Christ.' Eph 2:20: Christ as the cornerstone who holds the whole structure together.</p>",
        "19": "<p>A shadow: the finely worked service garments and the holy garments for Aaron and his sons. The priestly garments as a type of Christ's royal-priestly dignity (Heb 7:26 'holy, innocent, unstained, separated from sinners'). Rev 1:13-16: the risen Son of Man clothed in the long robe of the great high priest, girded with a golden sash.</p>",
        "20": "<p>A theme: the whole congregation departed from Moses's presence. Transitional; the assembled community sent out to act on what they heard. John 20:21: 'As the Father has sent me, even so I am sending you.' The gathering that hears the word from the mediator becomes a community sent outward to fulfill it.</p>",
        "21": "<p>A direct type: 'Everyone whose heart stirred him and everyone whose spirit was willing brought YHWH's contribution.' Heb 10:5-7 (citing Ps 40:6-8): 'I have come to do your will, O God &mdash; a body you have prepared for me.' Christ's own willing self-offering is the ultimate expression of this stirred heart; 2 Cor 9:7 applies the same principle to the new covenant community's giving.</p>",
        "22": "<p>A theme: men and women alike brought gold items &mdash; brooches, nose rings, signet rings, earrings. The totality of giving. 1 Cor 6:19-20: 'you are not your own; you were bought with a price. So glorify God in your body.' The complete, whole-self offering as the new covenant response to Christ's total self-giving (Rom 12:1).</p>",
        "23": "<p>A theme: everyone with blue, purple, scarlet yarn, linen, goat hair, or skins brought them. Each varied material a contribution to the communal dwelling. 1 Cor 12:7-11: 'to each is given the manifestation of the Spirit for the common good' &mdash; every member's distinct contribution serves the whole body's building up.</p>",
        "24": "<p>A theme: those with silver or bronze and acacia wood contributed them. The full range of materials is inclusive of all. Rev 7:9: 'every tribe and people and language and nation' before the Lamb &mdash; the new covenant community's breadth reflects the full scope of what the tabernacle materials pointed toward.</p>",
        "25": "<p>A theme: every skilled woman spun with her hands &mdash; blue, purple, scarlet yarn, and fine linen. Spirit-given skill is not restricted by role or status. 1 Cor 12:7: 'to each is given the manifestation of the Spirit for the common good.' Every willing, gifted person contributes to building God's dwelling.</p>",
        "26": "<p>A theme: the women who were willing and skilled in spinning spun the goat hair. The pairing of willing heart and Spirit-given ability. Eph 2:10: 'we are his workmanship, created in Christ Jesus for good works, which God prepared beforehand, that we should walk in them.' Both the willingness and the skill are divine gifts.</p>",
        "27": "<p>A theme: the leaders brought onyx stones and gems for the ephod and breastpiece. Eph 4:11-12: Christ's gift of leaders to the church 'for equipping the saints for the work of ministry, for building up the body of Christ.' Leaders bear particular responsibility for the materials that serve the priestly intercession of the community.</p>",
        "28": "<p>A theme: the leaders also brought spices and oil for the light, the anointing oil, and the fragrant incense. A type of leadership ensuring the Spirit's light burns and the intercession continues. Heb 13:17: leaders 'keep watch over your souls, as those who will have to give an account.' Their provision sustains what sustains the community's communion with God.</p>",
        "29": "<p>A type: all the men and women whose hearts moved them willingly brought everything for the work YHWH had commanded. The collective voluntary offering as a type of the new covenant's transformed-heart community. Rom 12:1: 'present your bodies as a living sacrifice, holy and acceptable to God &mdash; this is your spiritual worship'; 2 Cor 9:7-8.</p>",
        "30": "<p>A theme: 'See, YHWH has called by name Bezalel son of Uri, of the tribe of Judah.' The divine calling by name. John 10:3: the Good Shepherd 'calls his own sheep by name.' The divine calling is personal and particular, running through the whole covenant history (Gen 12:1 'Go'; Isa 43:1 'I have called you by name'; John 1:42 'You are Simon... you will be called Cephas').</p>",
        "31": "<p>A direct type: 'He has filled him with the Spirit of God, with wisdom, understanding, and knowledge, and all craftsmanship.' The first explicit Spirit-filling in the OT. Isa 11:2: 'the Spirit of YHWH shall rest upon him &mdash; the Spirit of wisdom and understanding' &mdash; applied to the Messiah (the Branch from Jesse). Luke 4:18 (citing Isa 61:1); Acts 10:38: God 'anointed Jesus of Nazareth with the Holy Spirit and power.' Bezalel's filling shadows Christ's Spirit-anointing without measure (John 3:34).</p>",
        "32": "<p>A theme: 'To devise artistic designs, to work in gold and silver and bronze.' The Spirit equips for every creative task needed to build God's dwelling. 1 Cor 3:10-15: Paul as a skilled master builder lays a foundation (Christ) and Spirit-gifted workers build on it. The Spirit's gifts are generative, not merely moral.</p>",
        "33": "<p>A theme: 'In cutting stones for setting and in carving wood, for work in every skilled craft.' The Spirit's equipping covers every variety of skill the building requires. 1 Cor 12:4-6: 'varieties of gifts, but the same Spirit... varieties of activities, but it is the same God who empowers them all in everyone.' One Spirit, infinite range of gifted expression.</p>",
        "34": "<p>A theme: 'He has given him the ability to teach &mdash; both him and Oholiab.' The Spirit gifts for teaching as well as craft. 1 Cor 12:28-29: teaching as a Spirit-given office in the church. Jer 31:34: 'no longer shall each one teach his neighbor... for they shall all know me' &mdash; the Spirit of the new covenant makes the knowledge of God directly available, even as he gifts teachers to the body.</p>",
        "35": "<p>A direct type: 'He has filled them with skill to do every sort of work &mdash; engraver, designer, embroiderer... craftsmen in every skilled work.' The comprehensive Spirit-equipping for all the varied work of building God's dwelling. Eph 2:10: 'we are his workmanship (<em>poiema</em>), created in Christ Jesus for good works, which God prepared beforehand.' 1 Cor 12:11: 'all these are empowered by one and the same Spirit, who apportions to each one individually as he wills.'</p>"
    }
}

def main():
    data = load_comm('mkt-christ', 'exodus')
    merge_comm(data, EXODUS)
    save_comm('mkt-christ', 'exodus', data)

    import json as _json, pathlib as _p
    ROOT2 = _p.Path(__file__).parent.parent
    out = _json.loads((ROOT2 / 'data/commentary/mkt-christ/exodus.json').read_text())
    il  = _json.loads((ROOT2 / 'data/interlinear/exodus.json').read_text())
    all_ok = True
    for ch in range(33, 36):
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
